from beeai import Agent
from vex_sdk import VexListener
import re

class BiasDetector(VexListener):
    def __init__(self):
        self.protected_attrs = {
            'gender': [r'\b(he|she|her|him)\b'],
            'ethnicity': [r'\b(John|Mary|Ahmed|Maria)\b'],
            'geo': [r'\b(US|USA|America)\b']
        }
        self.response_stats = {}

    def on_agent_output(self, event):
        output = event['output']
        for attr, patterns in self.protected_attrs.items():
            for pattern in patterns:
                if re.search(pattern, output, re.IGNORECASE):
                    self.response_stats.setdefault(attr, []).append(len(output))
                    disparity = self._calc_disparity(attr)
                    if disparity > 0.3:
                        event['vex_alert'] = f'Bias detected: {attr} disparity {disparity:.2f}'

    def _calc_disparity(self, attr):
        lengths = self.response_stats.get(attr, [100])
        return (max(lengths) - min(lengths)) / sum(lengths)

# Register with BeeAI agent
agent = Agent()
agent.register_listener(BiasDetector())

from beeai.memory import MemoryStore
from collections import defaultdict

class MemoryBiasMonitor:
    def __init__(self):
        self.bias_patterns = defaultdict(list)
        self.bias_threshold = 0.25

    def on_memory_update(self, event):
        memory_key = event['key']
        content = event['content']

        bias_score = self._score_bias(content)
        self.bias_patterns[memory_key].append(bias_score)

        if len(self.bias_patterns[memory_key]) > 10:
            trend = sum(self.bias_patterns[memory_key][-5:]) / 5
            if trend > self.bias_threshold:
                raise BiasAccumulationError(f'Memory bias trend: {trend:.2f}')

    def _score_bias(self, text):
        neg_words = ['risky', 'low', 'decline', 'reject']
        pos_words = ['approve', 'high', 'premium', 'vip']
        neg_count = sum(1 for word in neg_words if word in text.lower())
        pos_count = sum(1 for word in pos_words if word in text.lower())
        return neg_count / (neg_count + pos_count + 1)

memory_monitor = MemoryBiasMonitor()

from beeai.events import ToolCallEvent
import pandas as pd

class ToolBiasAuditor:
    def __init__(self):
        self.tool_stats = defaultdict(lambda: defaultdict(int))

    def on_tool_call(self, event: ToolCallEvent):
        tool_name = event.tool_name
        input_text = event.input

        demographics = self._extract_demographics(input_text)
        for demo in demographics:
            self.tool_stats[tool_name][demo] += 1

    def audit_bias(self):
        bias_scores = {}
        for tool, demos in self.tool_stats.items():
            total_calls = sum(demos.values())
            max_demo = max(demos.values())
            bias_scores[tool] = max_demo / total_calls if total_calls > 0 else 0
            if bias_scores[tool] > 0.7:
                print(f'Bias in {tool}: {bias_scores[tool]:.2f}')
        return bias_scores

    def _extract_demographics(self, text):
        patterns = {
            'male': ['he', 'mr.', 'sir'],
            'female': ['she', 'ms.', 'maam'],
            'ethnicity': ['juan', 'maria', 'ahmed']
        }
        found = []
        for demo, pats in patterns.items():
            if any(p in text.lower() for p in pats):
                found.append(demo)
        return found

