from beeai.memory import BalancedMemory
from typing import Dict, Any

class DemographicBalancedMemory(BalancedMemory):
    def __init__(self):
        super().__init__()
        self.demo_counters = defaultdict(int)
        self.max_per_demo = 100

    def store(self, key: str, value: str, metadata: Dict[str, Any]):
        demo_tags = self._extract_demo_tags(metadata)

        for tag in demo_tags:
            if self.demo_counters[tag] < self.max_per_demo:
                self.demo_counters[tag] += 1
                super().store(key, value, metadata)
                return

    def retrieve(self, query: str, limit: int = 5):
        memories = super().retrieve(query, limit * 3)
        # Re-rank by demographic balance
        balanced_memories = self._balance_demographics(memories)
        return balanced_memories[:limit]

    def _extract_demo_tags(self, metadata):
        tags = []
        if 'gender' in metadata:
            tags.append(metadata['gender'])
        if 'region' in metadata:
            tags.append(metadata['region'])
        return tags

balanced_memory = DemographicBalancedMemory()

from beeai.tools import ToolValidator

class FairnessToolValidator(ToolValidator):
    def __init__(self):
        self.protected_attrs = ['gender', 'ethnicity', 'age']

    def validate_call(self, tool_name: str, params: dict, context: str):
        # Generate counterfactuals
        counterfacts = self._generate_counterfactuals(context)

        for cf_context in counterfacts:
            cf_result = self._simulate_tool_call(tool_name, params, cf_context)
            if cf_result != self._simulate_tool_call(tool_name, params, context):
                raise FairnessViolation(
                    f'Tool {tool_name} fails counterfactual fairness'
                )
        return True

    def _generate_counterfactuals(self, context: str):
        # Swap protected attributes
        counterfacts = []
        if 'he' in context:
            counterfacts.append(context.replace('he', 'she'))
        if 'John' in context:
            counterfacts.append(context.replace('John', 'Jamal'))
        return counterfacts[:2]

fair_validator = FairnessToolValidator()
